import React from 'react';
import { Link } from 'react-router-dom';

const Header = () => {
  return (
    <header style={{ backgroundColor: '#f8f9fa', padding: '10px 20px', borderBottom: '1px solid #e9ecef', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
      <div style={{ display: 'flex', alignItems: 'center' }}>
        <h2 style={{ margin: 0, color: '#6c757d' }}>📚 LibraryHub</h2>
      </div>
      <nav style={{ display: 'flex', alignItems: 'center' }}>
        <Link to="/" style={{ margin: '0 15px', color: '#495057', textDecoration: 'none', fontWeight: '500' }}>Home</Link>
        <Link to="/browse" style={{ margin: '0 15px', color: '#495057', textDecoration: 'none', fontWeight: '500' }}>Browse Books</Link>
        <Link to="/categories" style={{ margin: '0 15px', color: '#495057', textDecoration: 'none', fontWeight: '500' }}>Categories</Link>
        <Link to="/about" style={{ margin: '0 15px', color: '#495057', textDecoration: 'none', fontWeight: '500' }}>About</Link>
      </nav>
      <div>
        <Link to="/login" style={{ margin: '0 10px', padding: '8px 16px', backgroundColor: '#007bff', color: 'white', textDecoration: 'none', borderRadius: '5px', fontWeight: '500' }}>Login</Link>
        <Link to="/register" style={{ margin: '0 10px', padding: '8px 16px', backgroundColor: '#28a745', color: 'white', textDecoration: 'none', borderRadius: '5px', fontWeight: '500' }}>Sign Up</Link>
      </div>
    </header>
  );
};

export default Header;
